import Link from "next/link";
import { AppShell } from "@/components/app-shell";
import { getAuthContext } from "@/lib/firebase/auth";
import { boardsRepository } from "@/lib/repositories/boards-repository";
import { knowledgeRepository } from "@/lib/repositories/knowledge-repository";
import { skillsRepository } from "@/lib/repositories/skills-repository";

export default async function Page() {
  const auth = await getAuthContext();
  if (!auth?.workspaceId) {
    return <AppShell title="Dashboard"><p>Sessão não encontrada.</p></AppShell>;
  }

  const [boards, knowledge, skills] = await Promise.all([
    boardsRepository.list(auth.workspaceId),
    knowledgeRepository.list(auth.workspaceId),
    skillsRepository.list(auth.workspaceId),
  ]);

  return (
    <AppShell title="Dashboard">
      <section className="grid gap-4 sm:grid-cols-3">
        <article className="rounded border bg-white p-4"><p className="text-sm text-gray-600">Boards</p><p className="text-2xl font-semibold">{boards.length}</p></article>
        <article className="rounded border bg-white p-4"><p className="text-sm text-gray-600">Knowledge</p><p className="text-2xl font-semibold">{knowledge.length}</p></article>
        <article className="rounded border bg-white p-4"><p className="text-sm text-gray-600">Skills</p><p className="text-2xl font-semibold">{skills.length}</p></article>
      </section>
      <section className="rounded border bg-white p-4">
        <h2 className="mb-3 font-semibold">Acessos rápidos</h2>
        <div className="flex gap-2 text-sm">
          <Link href="/board" className="rounded border px-3 py-1">Board</Link>
          <Link href="/knowledge" className="rounded border px-3 py-1">Knowledge</Link>
          <Link href="/skills" className="rounded border px-3 py-1">Skills</Link>
        </div>
      </section>
    </AppShell>
  );
}
